import { Article } from "../types";

const DB_NAME = 'NephroUpdateDB';
const STORE_NAME = 'offline_articles';
const DB_VERSION = 2; // Incremented version to support schema changes if needed (though IndexedDB is schema-less for objects)

export interface OfflineRecord {
    id: string;
    article: Article;
    htmlContent: string;
    timestamp: number;
    hasFullText?: boolean;
    localPdfData?: string; // Base64 PDF
    fullTextContent?: string; // Extracted text
}

const openDB = (): Promise<IDBDatabase> => {
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, DB_VERSION);

        request.onupgradeneeded = (event) => {
            const db = (event.target as IDBOpenDBRequest).result;
            if (!db.objectStoreNames.contains(STORE_NAME)) {
                db.createObjectStore(STORE_NAME, { keyPath: 'id' });
            }
        };

        request.onsuccess = (event) => {
            resolve((event.target as IDBOpenDBRequest).result);
        };

        request.onerror = (event) => {
            reject((event.target as IDBOpenDBRequest).error);
        };
    });
};

export const saveArticleOffline = async (article: Article, htmlContent: string, isFullText: boolean = false): Promise<void> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readwrite');
        const store = transaction.objectStore(STORE_NAME);

        // Preserve existing PDF data if not provided in this update, or update if provided
        const requestGet = store.get(article.id);

        requestGet.onsuccess = () => {
            const existing = requestGet.result as OfflineRecord | undefined;

            const record: OfflineRecord = {
                id: article.id,
                article: article,
                htmlContent: htmlContent,
                timestamp: Date.now(),
                hasFullText: isFullText,
                localPdfData: article.localPdfData || existing?.localPdfData,
                fullTextContent: article.fullTextContent || existing?.fullTextContent
            };

            const requestPut = store.put(record);
            requestPut.onsuccess = () => resolve();
            requestPut.onerror = () => reject(requestPut.error);
        };

        requestGet.onerror = () => reject(requestGet.error);
    });
};

export const getOfflineArticle = async (id: string): Promise<OfflineRecord | undefined> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readonly');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.get(id);

        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
};

export const getAllOfflineIds = async (): Promise<Set<string>> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readonly');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.getAllKeys();

        request.onsuccess = () => {
            const keys = request.result as string[];
            resolve(new Set(keys));
        };
        request.onerror = () => reject(request.error);
    });
};

// New function to get status of all downloads
export const getOfflineStatusMap = async (): Promise<Record<string, boolean>> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readonly');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.getAll();

        request.onsuccess = () => {
            const records = request.result as OfflineRecord[];
            const statusMap: Record<string, boolean> = {};
            records.forEach(rec => {
                // Considered downloaded if it has HTML full text OR a PDF attached
                statusMap[rec.id] = !!rec.hasFullText || !!rec.localPdfData;
            });
            resolve(statusMap);
        };
        request.onerror = () => reject(request.error);
    });
};

export const deleteOfflineArticle = async (id: string): Promise<void> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readwrite');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.delete(id);

        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error);
    });
};

export const clearOfflineStorage = async (): Promise<void> => {
     const db = await openDB();
     return new Promise((resolve, reject) => {
        const transaction = db.transaction(STORE_NAME, 'readwrite');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.clear();
        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error);
    });
};

import * as pdfjsLib from 'pdfjs-dist';

// Configure PDF.js worker
// Using esm.sh CDN version matching the main library import in index.html
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@4.0.379/build/pdf.worker.min.mjs';

/**
 * Converts a File object to a Base64 string.
 * Used for storing the visual PDF representation.
 */
export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      // Remove Data URI prefix to get pure Base64 if needed, 
      // but usually for PDF display we want the prefix or can handle it.
      // Here we return the full Data URL (e.g. data:application/pdf;base64,...)
      resolve(reader.result as string);
    };
    reader.onerror = (error) => reject(error);
  });
};

/**
 * Extracts raw text content from a PDF file using PDF.js.
 * This text is used to feed the AI context.
 */
export const extractTextFromPdf = async (file: File): Promise<string> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
    const pdfDocument = await loadingTask.promise;

    let fullText = '';

    // Iterate through all pages
    for (let pageNum = 1; pageNum <= pdfDocument.numPages; pageNum++) {
      const page = await pdfDocument.getPage(pageNum);
      const textContent = await page.getTextContent();

      const pageText = textContent.items
        .map((item: any) => item.str)
        .join(' ');

      fullText += `[Page ${pageNum}]\n${pageText}\n\n`;
    }

    return fullText.trim();
  } catch (error) {
    console.error("Error extracting text from PDF:", error);
    throw new Error("Failed to parse PDF content.");
  }
};

/**
 * Combined function to process a PDF upload:
 * 1. Converts to Base64 for storage/display.
 * 2. Extracts text for AI.
 */
export const processPdfUpload = async (file: File): Promise<{ base64: string; text: string }> => {
    const [base64, text] = await Promise.all([
        fileToBase64(file),
        extractTextFromPdf(file)
    ]);
    return { base64, text };
};

import React, { useEffect, useRef, useState } from 'react';
import * as pdfjsLib from 'pdfjs-dist';
import { ChevronLeft, ChevronRight, ZoomIn, ZoomOut, Loader2, AlertCircle } from 'lucide-react';

interface PdfViewerProps {
  pdfData: string; // Base64 Data URL
  isDarkMode: boolean;
}

const PdfViewer: React.FC<PdfViewerProps> = ({ pdfData, isDarkMode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [pdfDoc, setPdfDoc] = useState<pdfjsLib.PDFDocumentProxy | null>(null);
  const [pageNum, setPageNum] = useState(1);
  const [scale, setScale] = useState(1.2);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const renderTaskRef = useRef<any>(null);

  useEffect(() => {
    const loadPdf = async () => {
      try {
        setLoading(true);
        setError(null);

        // Ensure worker is set (redundant check if set in service, but good for safety)
        if (!pdfjsLib.GlobalWorkerOptions.workerSrc) {
             pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@4.0.379/build/pdf.worker.min.mjs';
        }

        const loadingTask = pdfjsLib.getDocument(pdfData);
        const doc = await loadingTask.promise;
        setPdfDoc(doc);
        setPageNum(1);
        setLoading(false);
      } catch (err: any) {
        console.error("Error loading PDF:", err);
        setError("No se pudo renderizar el PDF.");
        setLoading(false);
      }
    };

    if (pdfData) {
      loadPdf();
    }
  }, [pdfData]);

  useEffect(() => {
    const renderPage = async () => {
      if (!pdfDoc || !canvasRef.current) return;

      // Cancel previous render if exists
      if (renderTaskRef.current) {
        renderTaskRef.current.cancel();
      }

      try {
        const page = await pdfDoc.getPage(pageNum);
        const viewport = page.getViewport({ scale });
        const canvas = canvasRef.current;
        const context = canvas.getContext('2d');

        if (!context) return;

        // Set dimensions
        canvas.height = viewport.height;
        canvas.width = viewport.width;

        const renderContext = {
          canvasContext: context,
          viewport: viewport,
        };

        const renderTask = page.render(renderContext);
        renderTaskRef.current = renderTask;
        await renderTask.promise;
      } catch (err: any) {
        if (err.name !== 'RenderingCancelledException') {
            console.error("Page render error:", err);
        }
      }
    };

    renderPage();
  }, [pdfDoc, pageNum, scale]);

  const changePage = (offset: number) => {
    if (!pdfDoc) return;
    setPageNum(prev => Math.min(Math.max(1, prev + offset), pdfDoc.numPages));
  };

  const changeZoom = (delta: number) => {
    setScale(prev => Math.min(Math.max(0.5, prev + delta), 3.0));
  };

  if (loading) {
      return (
          <div className="flex flex-col items-center justify-center h-64 text-slate-400">
              <Loader2 size={32} className="animate-spin mb-2" />
              <p className="text-xs uppercase tracking-widest font-bold">Cargando Documento...</p>
          </div>
      );
  }

  if (error) {
      return (
          <div className="flex flex-col items-center justify-center h-64 text-red-400">
              <AlertCircle size={32} className="mb-2" />
              <p className="text-xs font-bold">{error}</p>
          </div>
      );
  }

  return (
    <div className={`flex flex-col h-full w-full ${isDarkMode ? 'bg-slate-900' : 'bg-slate-100'}`}>

      {/* Toolbar */}
      <div className={`flex items-center justify-between p-2 border-b ${isDarkMode ? 'bg-slate-950 border-slate-800' : 'bg-white border-slate-200'} sticky top-0 z-10`}>
          <div className="flex items-center gap-2">
              <button onClick={() => changeZoom(-0.2)} className={`p-1.5 rounded-lg hover:bg-black/5 dark:hover:bg-white/5 ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}><ZoomOut size={18} /></button>
              <span className="text-[10px] font-mono font-bold w-8 text-center">{Math.round(scale * 100)}%</span>
              <button onClick={() => changeZoom(0.2)} className={`p-1.5 rounded-lg hover:bg-black/5 dark:hover:bg-white/5 ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}><ZoomIn size={18} /></button>
          </div>

          <div className="flex items-center gap-2">
              <button onClick={() => changePage(-1)} disabled={pageNum <= 1} className={`p-1.5 rounded-lg disabled:opacity-30 hover:bg-black/5 dark:hover:bg-white/5 ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}><ChevronLeft size={18} /></button>
              <span className="text-[10px] font-bold uppercase tracking-widest">Page {pageNum} / {pdfDoc?.numPages || '-'}</span>
              <button onClick={() => changePage(1)} disabled={!pdfDoc || pageNum >= pdfDoc.numPages} className={`p-1.5 rounded-lg disabled:opacity-30 hover:bg-black/5 dark:hover:bg-white/5 ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}><ChevronRight size={18} /></button>
          </div>
      </div>

      {/* Canvas Container */}
      <div className="flex-1 overflow-auto flex justify-center p-4">
          <div className="shadow-2xl">
             <canvas ref={canvasRef} className="block bg-white rounded-sm" />
          </div>
      </div>
    </div>
  );
};

